from string_utils.generation import secure_random_hex

def test__secure_random_hex_invalid_inputs():
    try:
        secure_random_hex(-5)
        print(f"Expected ValueError for negative input; no error raised.")
    except ValueError as e:
        print(f"Caught ValueError as expected for input -5: {e}")

    try:
        secure_random_hex('abc')
        print(f"Expected ValueError for non-integer input; no error raised.")
    except ValueError as e:
        print(f"Caught ValueError as expected for input 'abc': {e}")
